function solve(c, connections, queries) {
    // Initialize Union-Find structure for the grid
    const uf = new UnionFind(c);

    // Process connections to build the grid
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // For each node, store the representative (root) of its set
    const root = new Array(c + 1);
    for (let i = 1; i <= c; i++) {
        root[i] = uf.find(i);
    }

    // For each root, store the minimum node in its set
    const minNode = new Map();
    for (let i = 1; i <= c; i++) {
        const r = root[i];
        if (!minNode.has(r)) {
            minNode.set(r, i);
        }
    }

    // Process queries
    const result = [];
    const offline = new Array(c + 1).fill(false);

    for (const [type, x] of queries) {
        if (type === 1) {
            // Maintenance check query
            if (offline[x]) {
                // x is offline, find the minimum online node in its grid
                const r = root[x];
                const min = minNode.get(r);
                if (min === undefined) {
                    result.push(-1);
                } else {
                    result.push(min);
                }
            } else {
