fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    // Union-Find data structure
    class UnionFind(val n: Long) {
        val parent = LongArray(n + 1)
        val rank = LongArray(n + 1)

        init {
            for (i in 1..n) {
                parent[i] = i
                rank[i] = 1
            }
        }

        fun find(x: Long): Long {
            if (parent[x] != x) {
                parent[x] = find(parent[x])
            }
            return parent[x]
        }

        fun union(x: Long, y: Long) {
            val xRoot = find(x)
            val yRoot = find(y)
            if (xRoot == yRoot) return
            if (rank[xRoot] < rank[yRoot]) {
                parent[xRoot] = yRoot
            } else {
                parent[yRoot] = xRoot
                if (rank[xRoot] == rank[yRoot]) {
                    rank[xRoot]++
                }
            }
        }
    }

    val uf = UnionFind(c)

    // Process connections to build the grid
    for (connection in connections) {
        val u = connection[0]
        val v = connection[1]
        uf.union(u, v)
    }

    // For each node, store the representative (root) of its set
    val root = LongArray(c + 1)
    for (i in 1..c) {
        root[i] = uf.find(i)
    }

    // For each root, store the minimum node in its set
    val minNode = mutableMapOf<Long, Long>()
    for (i in 1..c) {
        val r = root[i]
        if (!minNode.containsKey(r)) {
            minNode[r] = i
        } else {
            minNode[r] = minOf(minNode[r]!!, i)
        }
    }

    // Process queries
    val result = LongArray(queries.size)
    val offline = BooleanArray(c + 1)

    var index = 0
    for (query in queries) {
        val type = query[0]
        val x = query[1]
        if (type == 1L) {
            // Maintenance check query
            if (offline[x.toInt()]) {
                // x is offline, find the minimum online node in its grid
                val r = root[x.toInt()]
                val min = minNode[r]
                if (min == null) {
                    result[index++] = -1
                } else {
                    result[index++] = min
                }
            } else {
                // x is online, itself handles the check
                result[index++] = x
            }
        } else {
            // Offline query
            offline[x.toInt()] = true
            // Update the minNode map
            val r = root[x.toInt()]
